	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;&lt;strong&gt;सही जवाब बी है&lt;/strong&gt;&lt;/p&gt;&lt;p&gt; &lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;नोट: आधिकारिक उत्तर कुंजी के अनुसार सही उत्तर 2, 3, 4 हैं।&lt;/span&gt;&lt;/strong&gt;&lt;br /&gt; &lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;महत्वपूर्ण बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;table border=&quot;1&quot;&gt;&lt;thead&gt;&lt;tr&gt;&lt;th&gt; ग्रह&lt;/th&gt;&lt;th&gt; चंद्रमाओं की संख्या&lt;/th&gt;&lt;/tr&gt;&lt;/thead&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td&gt; मंगल ग्रह&lt;/td&gt;&lt;td&gt; 2&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt; बृहस्पति&lt;/td&gt;&lt;td&gt; 95&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt; यूरेनस&lt;/td&gt;&lt;td&gt; 28&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt; नेपच्यून&lt;/td&gt;&lt;td&gt; 16&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;p&gt; &lt;strong&gt;मंगल ग्रह:&lt;/strong&gt;&lt;/p&gt;&lt;ul&gt;&lt;li&gt; मंगल ग्रह के दो चंद्रमा हैं, जिनका नाम फोबोस और डीमोस है।&lt;/li&gt;&lt;li&gt; ये छोटे और अनियमित आकार के होते हैं, और माना जाता है कि ये पकड़े गए क्षुद्रग्रह हैं।&lt;/li&gt;&lt;/ul&gt;&lt;p&gt; &lt;strong&gt;बृहस्पति&lt;/strong&gt; :&lt;/p&gt;&lt;ul&gt;&lt;li&gt; &lt;strong&gt;बृहस्पति के पास सौर मंडल में सबसे अधिक चंद्रमा हैं, सितंबर 2021 तक इसके 72 चंद्रमाओं की&lt;/strong&gt; पुष्टि हो चुकी है।&lt;/li&gt;&lt;li style=&quot;text-align: justify;&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;बृहस्पति के 13 नए चंद्रमाओं की खोज के बाद, इसके प्राकृतिक उपग्रहों की कुल संख्या 95 हो गई है, जो सभी ग्रहों में सबसे अधिक है।&lt;/span&gt;&lt;/li&gt;&lt;li&gt; इसके कुछ सबसे प्रसिद्ध चंद्रमाओं में आयो, यूरोपा, गैनीमेड और कैलिस्टो शामिल हैं।&lt;/li&gt;&lt;/ul&gt;&lt;p&gt; &lt;strong&gt;यूरेनस:&lt;/strong&gt;&lt;/p&gt;&lt;ul&gt;&lt;li&gt; यूरेनस के 28 ज्ञात चंद्रमा हैं।&lt;/li&gt;&lt;li&gt; इसके कुछ सबसे बड़े चंद्रमा मिरांडा, एरियल, अम्ब्रील, टाइटेनिया और ओबेरॉन हैं।&lt;/li&gt;&lt;/ul&gt;&lt;p&gt; &lt;strong&gt;नेपच्यून&lt;/strong&gt; :&lt;/p&gt;&lt;ul&gt;&lt;li&gt; सितंबर 2021 तक नेपच्यून के 16 ज्ञात चंद्रमा हैं।&lt;/li&gt;&lt;li&gt; इसका सबसे बड़ा चंद्रमा, ट्राइटन, सौर मंडल में एकमात्र ऐसा बड़ा चंद्रमा होने के लिए उल्लेखनीय है जो अपने ग्रह के घूर्णन की विपरीत दिशा में परिक्रमा करता है।&lt;/li&gt;&lt;/ul&gt;&lt;p&gt; &lt;strong&gt;कुल मिलाकर, प्रत्येक ग्रह के चंद्रमाओं की संख्या में परिवर्तन हो सकता है क्योंकि अधिक चंद्रमाओं की खोज या पुष्टि की जाती है।&lt;br /&gt; &lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;1&quot; style=&quot;color: rgb(33, 37, 41); width: 350px;&quot;&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;रैंक&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;ग्रह का नाम&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;प्राकृतिक उपग्रहों की संख्या&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 1&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; शनि ग्रह&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 146&lt;/p&gt;
			&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt;2&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; बृहस्पति&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;width: 174px;&quot;&gt;&lt;p align=&quot;center&quot;&gt; 95&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 3&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; यूरेनस&lt;/p&gt;&lt;/td&gt;&lt;td style=&quot;width: 174px;&quot;&gt;&lt;p align=&quot;center&quot;&gt; 28&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 4&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; नेपच्यून&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 16&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 5&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; मंगल ग्रह&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 2&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 6&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; धरती&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; 1&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: bolder;&quot;&gt;7&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;शुक्र&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;0&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: bolder;&quot;&gt;8&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;बुध&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td&gt;&lt;p align=&quot;center&quot;&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;0&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;

questions.statement:
&lt;p&gt;Consider the following features of soil.&lt;/p&gt;

&lt;p&gt;(A) Colour&lt;/p&gt;

&lt;p&gt;(B) Texture&lt;/p&gt;

&lt;p&gt;(C) Thickness&lt;/p&gt;

&lt;p&gt;(D) Amount of humus&lt;/p&gt;

&lt;p&gt;(E) Permeability&lt;/p&gt;

&lt;p&gt;Which of the above features are determined by parent rock.&lt;/p&gt;<br>&lt;p&gt;मृदा के निम्नलिखित लक्षणों पर विचार कीजिए:&lt;/p&gt;

&lt;p&gt;(A) रंग&lt;/p&gt;

&lt;p&gt;(B) बनावट&lt;/p&gt;

&lt;p&gt;(C) मोटाई&lt;/p&gt;

&lt;p&gt;(D) ह्यूमस की मात्रा&lt;/p&gt;

&lt;p&gt;(E) पारगम्यता&lt;/p&gt;

&lt;p&gt;उपरोक्त में से कौन से लक्षण मूल&amp;nbsp;चट्टान द्वारा निर्धारित होते हैं।&lt;/p&gt;

questions.explanation:
&lt;p&gt;&lt;strong&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(A), (B) and (E)&lt;/span&gt;&lt;/strong&gt;&lt;br /&gt;
&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Among the listed features of soil, color (A),&amp;nbsp;(B) Texture&lt;/strong&gt;&lt;strong&gt;, and permeability (E) are determined by the parent rock. Here&amp;#39;s an explanation for each:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;(A) Color:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The color of soil can be influenced by the minerals present in the parent rock.&lt;/li&gt;
	&lt;li&gt;Different minerals give rise to different colors, such as reddish-brown, yellowish-brown, gray, or black. For example, iron-rich minerals can give soils a reddish color.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;(B)&amp;nbsp;Texture:&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;Soil texture refers to the relative proportions of sand, silt, and clay particles in the soil.&lt;/li&gt;
	&lt;li&gt;The texture of soil is influenced by&amp;nbsp;by the parent rock.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;(E) Permeability:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Permeability refers to the ability of soil to allow water and air to pass through it.&lt;/li&gt;
	&lt;li&gt;The permeability of soil is influenced by the size and arrangement of soil particles, which, in turn, can be influenced by the parent rock.&lt;/li&gt;
	&lt;li&gt;For example, soil derived from rocks with larger particles, such as gravel or sand, tends to have higher permeability.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Features such as texture (B) and amount of humus (D) are not solely determined by the parent rock:&lt;/p&gt;

&lt;p&gt;(C)&amp;nbsp;Thickness&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(37, 37, 37);  &quot;&gt;Time determines the thickness of the soil profile.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;(D) Amount of humus:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Humus is the organic component of soil that is derived from the decomposition of plant and animal matter.&lt;/li&gt;
	&lt;li&gt;The amount of humus in the soil is primarily influenced by factors such as organic inputs, climate, and biological activity, rather than the parent rock.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Therefore, the correct answer is&amp;nbsp;(A), (B), and (E).&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;सही उत्तर &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(A), (B) और (E)&amp;nbsp;&lt;/span&gt;है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;मृदा की सूचीबद्ध विशेषताओं में, रंग (A), बनावट (B), और पारगम्यता (E) मूल चट्टान द्वारा निर्धारित की जाती है। यहां प्रत्येक के लिए एक स्पष्टीकरण दिया गया है:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(A)&lt;/span&gt; रंग:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मृदा का रंग मूल चट्टान में मौजूद खनिजों से प्रभावित हो सकता है।&lt;/li&gt;
	&lt;li&gt;विभिन्न खनिज अलग-अलग रंगों को जन्म देते हैं, जैसे- लाल-भूरा, पीला-भूरा, भूरा या काला आदि। उदाहरण के लिए, लौह युक्त खनिज मृदा&amp;nbsp;को लाल रंग दे सकते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;(B) बनावट:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मृदा&amp;nbsp;की बनावट मिट्टी में रेत, गाद और मिट्टी के कणों के सापेक्ष अनुपात को दर्शाती है।&lt;/li&gt;
	&lt;li&gt;मृदा&amp;nbsp;की बनावट मूल चट्टान से प्रभावित होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;(E) पारगम्यता:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पारगम्यता से तात्पर्य &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;मृदा के जल&amp;nbsp;&lt;/span&gt;और वायु को अपने अंदर से गुजरने देने की क्षमता से है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;मृदा&amp;nbsp;&lt;/span&gt;की पारगम्यता मिट्टी के कणों के आकार और व्यवस्था से प्रभावित होती है, जो बदले में मूल चट्टान से प्रभावित हो सकती है।&lt;/li&gt;
	&lt;li&gt;उदाहरण के लिए, बजरी या रेत जैसे बड़े कणों वाली चट्टानों से प्राप्त &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;मृदा&amp;nbsp;&lt;/span&gt;में पारगम्यता अधिक होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;मोटाई&amp;nbsp;(C) और ह्यूमस की मात्रा (D) जैसी विशेषताएं पूरी तरह से मूल चट्टान द्वारा निर्धारित नहीं होती हैं:&lt;/p&gt;

&lt;p&gt;(C) मोटाई:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;समय मृदा&amp;nbsp;की मोटाई निर्धारित करता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;(D) ह्यूमस की मात्रा:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ह्यूमस मृदा का कार्बनिक घटक है जो पौधे और पशु पदार्थ के अपघटन से प्राप्त होता है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;मृदा&amp;nbsp;&lt;/span&gt;में ह्यूमस की मात्रा मुख्य रूप से मूल चट्टान के &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;अतिरिक्त&amp;nbsp;&lt;/span&gt;कार्बनिक इनपुट, जलवायु और जैविक गतिविधि जैसे कारकों से प्रभावित होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः सही उत्तर &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(A), (B) और (E)&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

questions.statement:
&lt;p&gt;Consider the following statements about coral reefs and choose the correct option:&lt;/p&gt;

&lt;p&gt;(A) Corals are skeletons of large marine animals.&lt;/p&gt;

&lt;p&gt;(B) Coral reefs play an important role in protecting the coastline from erosion.&lt;/p&gt;

&lt;p&gt;(C) When the living polyps die, their skeletons are left and collection of these skeletons form coral island.&lt;/p&gt;<br>&lt;p&gt;प्रवाल भित्तियों के बारे में नीचे दिए गए कथनों पर विचार कीजिए और सही विकल्प का चयन कीजिए:&lt;/p&gt;

&lt;p&gt;(A) प्रवाल बड़े समुद्री जीवों के कंकाल हैं।&lt;/p&gt;

&lt;p&gt;(B) प्रवाल भित्तियाँ समुद्र तट को कटाव से रोकने में महत्त्वपूर्ण भूमिका निभाती हैं।&lt;/p&gt;

&lt;p&gt;(C) जब जीवित पॉलीप्स मरते है तब उनके कंकाल बच जाते हैं। इन कंकालों के इकट्ठे होने से प्रवाल द्वीप बनते हैं।&lt;/p&gt;

questions.explanation:
&lt;p&gt;&lt;strong&gt;The correct option is:&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(B) and (C) are true&lt;/span&gt;.&lt;/strong&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;(B) Coral reefs play an important role in protecting the coastline from erosion.&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;This statement is true.&lt;/li&gt;
	&lt;li&gt;Coral reefs, in particular,&amp;nbsp;can substantially reduce coastal flooding and erosion by dissipating as much as 97 percent of incident wave energy.&lt;/li&gt;
	&lt;li&gt;Reefs function like low-crested breakwaters, with hydrodynamic behavior well characterized by coastal engineering models.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;(C) When the living polyps die, their skeletons are left, and the collection of these skeletons forms a coral island.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;This statement is true.&lt;/li&gt;
	&lt;li&gt;Coral islands, also known as coral atolls or cays, are formed over long periods of time as coral polyps build their calcium carbonate skeletons.&lt;/li&gt;
	&lt;li&gt;When the polyps die, their skeletons remain and accumulate over time, eventually forming landmasses.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;(A) Corals are skeletons of large marine animals.&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;strong&gt;This statement is false.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Most structures that we call &amp;quot;coral&amp;quot; are, in fact, made up of hundreds to thousands of tiny coral creatures called polyps.&lt;/li&gt;
	&lt;li&gt;Each soft-bodied polyp&amp;mdash;most no thicker than a nickel&amp;mdash;secretes a hard outer skeleton of limestone (calcium carbonate) that attaches either to rock or the dead skeletons of other polyps.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;&lt;strong&gt;&amp;nbsp;विकल्प&amp;nbsp;(B) और (C) सही हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;b&gt;(B) प्रवाल भित्तियाँ समुद्र तट को कटाव से रोकने में महत्त्वपूर्ण भूमिका निभाती हैं।&lt;/b&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;b&gt;यह कथन सत्य है.&lt;/b&gt;&lt;/li&gt;
	&lt;li&gt;&lt;b&gt;मूंगा चट्टानें, विशेष रूप से, 97 प्रतिशत घटना तरंग ऊर्जा को नष्ट करके तटीय बाढ़ और कटाव को काफी हद तक कम कर सकती हैं।&lt;/b&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;(C) जब जीवित पॉलीप्स मरते हैं, तो उनके कंकाल बच जाते हैं, और इन कंकालों का संग्रह एक प्रवाल द्वीप बनते&amp;nbsp;है।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह कथन सत्य है।&lt;/li&gt;
	&lt;li&gt;प्रवाल द्वीप, जिन्हें प्रवाल द्वीप या केज़ के रूप में भी जाना जाता है, लंबे समय तक बनते हैं क्योंकि प्रवाल पॉलीप्स अपने कैल्शियम कार्बोनेट कंकाल का निर्माण करते हैं।&lt;/li&gt;
	&lt;li&gt;जब पॉलीप्स मरते हैं, तो उनके कंकाल बने रहते हैं और समय के साथ जमा होते जाते हैं, अंततः भूभाग का निर्माण करते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(88, 89, 91);&quot;&gt;(A) प्रवाल बड़े समुद्री जीवों के कंकाल हैं।&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;यह कथन सही&amp;nbsp;नहीं है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;अधिकांश संरचनाएं जिन्हें हम &amp;quot;मूंगा&amp;quot; कहते हैं, वास्तव में, सैकड़ों से हजारों छोटे मूंगा प्राणियों से बनी होती हैं जिन्हें पॉलीप्स कहा जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;The correct answer is&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;Nickel and Iron&lt;/span&gt;&lt;/strong&gt;&lt;br /&gt;
&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Earth is composed of several layers, each with distinct properties and compositions.&lt;/li&gt;
	&lt;li&gt;The Earth&amp;#39;s core, which is the innermost layer, is further divided into two main parts: the outer core and the inner core.&lt;/li&gt;
	&lt;li&gt;The inner core is a solid, dense sphere located at the center of the Earth, with a radius of approximately 1,220 kilometers (760 miles).&lt;/li&gt;
	&lt;li&gt;It is primarily composed of a combination of nickel and iron, often referred to as an iron-nickel alloy.&lt;/li&gt;
	&lt;li&gt;The temperatur&lt;strong&gt;e in the inner core is estimated to be between 5,000 and 7,000 degrees Celsius (&lt;/strong&gt;9,000 and 13,000 degrees Fahrenheit), which is similar to or even higher than the temperature on the surface of the Sun.&lt;/li&gt;
	&lt;li&gt;Despite these extremely high temperatures, the inner core remains solid due to the immense pressure exerted by the surrounding layers.&lt;/li&gt;
	&lt;li&gt;The pressure at the inner core is so great that it forces the nickel and ir&lt;strong&gt;on to remain in a solid state, even though they would typically be in a li&lt;/strong&gt;quid or gaseous state at such high temperatures under normal conditions.&lt;/li&gt;
	&lt;li&gt;Surrounding the inner core is the outer core, which is also composed of a mixture of nickel and iron, but in a molten, liquid state. The outer core&amp;#39;s movement generates Earth&amp;#39;s magnetic field through a process called the geodynamo.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;In summary, the innermost layer of Earth&amp;#39;s core is made up of nickel and iron, and it remains in a solid state due to the immense pressure from the layers above it.&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;img src=&quot;https://1.bp.blogspot.com/---pPX0d8B0A/VfhOFAr2YXI/AAAAAAAAAVg/jUwT806fv-4/s1600/Dis.png&quot; style=&quot;height: 242px; width: 350px;&quot; /&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;सही उत्तर निकल व लोहा है&lt;/strong&gt;&lt;br /&gt;
&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पृथ्वी कई परतों से बनी है, जिनमें से प्रत्येक में अलग-अलग गुण और रचनाएँ हैं।&lt;/li&gt;
	&lt;li&gt;पृथ्वी का कोर, जो सबसे भीतरी परत है, को आगे दो मुख्य भागों में विभाजित किया गया है: बाहरी कोर और आंतरिक कोर।&lt;/li&gt;
	&lt;li&gt;आंतरिक कोर पृथ्वी के केंद्र में स्थित एक ठोस, घना गोला है, जिसकी त्रिज्या लगभग 1,220 किलोमीटर (760 मील) है।&lt;/li&gt;
	&lt;li&gt;यह मुख्य रूप से निकल और लोहे के संयोजन से बना है, जिसे अक्सर लौह-निकल मिश्र धातु कहा जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;आंतरिक कोर में&lt;/strong&gt; तापमान &lt;strong&gt;5,000 और 7,000 डिग्री सेल्सियस&lt;/strong&gt; (9,000 और 13,000 डिग्री फ़ारेनहाइट) &lt;strong&gt;के बीच होने का अनुमान है&lt;/strong&gt;, जो सूर्य की सतह पर तापमान के समान या उससे भी अधिक है।&lt;/li&gt;
	&lt;li&gt;इन अत्यधिक उच्च तापमानों के बावजूद, आंतरिक कोर आसपास की परतों द्वारा डाले गए अत्यधिक दबाव के कारण ठोस रहता है।&lt;/li&gt;
	&lt;li&gt;आंतरिक कोर पर दबाव इतना अधिक है कि यह निकल और &lt;strong&gt;लोहे को ठोस अवस्था में रहने के लिए&lt;/strong&gt; मजबूर करता है, &lt;strong&gt;भले ही वे सामान्य परिस्थितियों में&lt;/strong&gt; ऐसे उच्च तापमान पर तरल या गैसीय अवस्था में हों।&lt;/li&gt;
	&lt;li&gt;आंतरिक कोर के चारों ओर बाहरी कोर है, जो निकल और लोहे के मिश्रण से बना है, लेकिन पिघला हुआ, तरल अवस्था में है। बाहरी कोर की गति जियोडाइनेमो नामक एक प्रक्रिया के माध्यम से पृथ्वी के चुंबकीय क्षेत्र को उत्पन्न करती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;संक्षेप में, पृथ्वी के कोर की सबसे भीतरी परत निकल और लोहे से बनी है, और यह ऊपर की परतों से अत्यधिक दबाव के कारण ठोस अवस्था में रहती है।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;img src=&quot;https://1.bp.blogspot.com/---pPX0d8B0A/VfhOFAr2YXI/AAAAAAAAAVg/jUwT806fv-4/s1600/Dis.png&quot; style=&quot;height: 242px; width: 350px;&quot; /&gt;&lt;/p&gt;

questions.statement:
&lt;p&gt;Consider the following statements about Meridians.&lt;/p&gt;

&lt;p&gt;The Meridians ________.&lt;/p&gt;

&lt;p&gt;(A) are lines of longitude&lt;/p&gt;

&lt;p&gt;(B) are parallel lines to equator&lt;/p&gt;

&lt;p&gt;(C) are semicircles and the distance between them decreases steadily towards pole until it becomes zero at the poles&lt;/p&gt;

&lt;p&gt;Choose the correct answer:&lt;/p&gt;<br>&lt;p&gt;मेरिडियन के बारे में निम्नलिखित कथनों पर विचार करें।&lt;/p&gt;

&lt;p&gt;मेरिडियन ________।&lt;/p&gt;

&lt;p&gt;(ए) देशांतर रेखाएं हैं&lt;/p&gt;

&lt;p&gt;(बी) भूमध्य रेखा के समानांतर रेखाएं हैं&lt;/p&gt;

&lt;p&gt;(सी) अर्धवृत्त हैं और उनके बीच की दूरी ध्रुव की ओर लगातार घटती जाती है जब तक कि ध्रुव पर यह शून्य नहीं हो जाती&lt;/p&gt;

&lt;p&gt;सही उत्तर का चयन करें:&lt;/p&gt;

questions.explanation:
&lt;p&gt;&lt;strong&gt;The correct option is: (A) and (C) are correct.&lt;/strong&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(A) Meridians are lines of longitude.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Meridians are imaginary lines that run from the North Pole to the South Pole on the Earth&amp;#39;s surface.&lt;/li&gt;
	&lt;li&gt;They help in defining the east-west positions of locations.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;(B) Meridians are not parallel lines to the equator.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;They intersect the equator and converge at the poles.&lt;/li&gt;
	&lt;li&gt;Meridians are perpendicular to the equator and meet at the poles.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(C) The statement is correct.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The distance between the longitudes decreases towards the poles. At the equator, the distance between 15 and 30&amp;deg; W longitudes is quite a lot, but as we move toward the poles this distance shrinks and eventually shrinks down to zero.&lt;/li&gt;
	&lt;li&gt;This distance is shortest at the Poles because all the meridians meet here.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Therefore, the correct option is (3) (A) and (C) are correct.&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;सही विकल्प है: (A) और (C) सही हैं।&lt;/strong&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;महत्वपूर्ण बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(A) मेरिडियन देशांतर की रेखाएं हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मेरिडियन काल्पनिक रेखाएँ हैं जो पृथ्वी की सतह पर उत्तरी ध्रुव से दक्षिणी ध्रुव तक चलती हैं।&lt;/li&gt;
	&lt;li&gt;वे स्थानों की पूर्व-पश्चिम स्थिति को परिभाषित करने में मदद करते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;(B) मेरिडियन भूमध्य रेखा के समानांतर रेखाएं नहीं हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वे भूमध्य रेखा को काटते हैं और ध्रुवों पर एकत्रित होते हैं।&lt;/li&gt;
	&lt;li&gt;मेरिडियन भूमध्य रेखा के लंबवत हैं और ध्रुवों पर मिलते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(C) कथन सही है।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ध्रुवों की ओर देशांतरों के बीच की दूरी कम हो जाती है। भूमध्य रेखा पर, 15 और 30&amp;deg; W देशांतर के बीच की दूरी काफी होती है, लेकिन जैसे-जैसे हम ध्रुवों की ओर बढ़ते हैं यह दूरी कम होती जाती है और अंततः शून्य हो जाती है।&lt;/li&gt;
	&lt;li&gt;ध्रुवों पर यह दूरी सबसे कम होती है क्योंकि सभी देशांतर रेखाएँ यहीं मिलती हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;इसलिए, सही विकल्प (3) है (A) और (C) सही हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;Warm current.&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Gulf Stream is an example of an ocean current. Ocean currents are continuous movements of water in the ocean, driven by various factors such as wind patterns, temperature differences, and Earth&amp;#39;s rotation.&lt;/li&gt;
	&lt;li&gt;They play a significant role in distributing heat around the planet, influencing weather patterns, and affecting marine ecosystems.&lt;/li&gt;
	&lt;li&gt;The Gulf Stream is a powerful warm ocean current that flows from the Gulf of Mexico along the eastern coast of the United States, before turning towards the northeast and crossing the Atlantic Ocean.&lt;/li&gt;
	&lt;li&gt;It transports warm water from the tropics to the North Atlantic, impacting the climate of the regions it passes through.&lt;/li&gt;
	&lt;li&gt;The Gulf Stream has a notable influence on the weather and climate of eastern North America and Western Europe.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;गर्म जलधाराओं का&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt; है।&lt;br /&gt;
&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;गल्फ स्ट्रीम महासागरीय धारा का एक उदाहरण है। महासागरीय धाराएँ समुद्र में जल की निरंतर गति हैं, जो पवन के पैटर्न, तापमान अंतर और पृथ्वी के घूर्णन जैसे विभिन्न कारकों से प्रेरित होती हैं।&lt;/li&gt;
	&lt;li&gt;वे ग्रह के चारों ओर ऊष्मा वितरित करने, मौसम के पैटर्न को प्रभावित करने और समुद्री पारिस्थितिक तंत्र को प्रभावित करने में महत्वपूर्ण भूमिका निभाते हैं।&lt;/li&gt;
	&lt;li&gt;गल्फ स्ट्रीम एक शक्तिशाली गर्म समुद्री धारा है जो उत्तर पूर्व की ओर मुड़ने और अटलांटिक महासागर को पार करने से पहले संयुक्त राज्य अमेरिका के पूर्वी तट के साथ मैक्सिको की खाड़ी से बहती है।&lt;/li&gt;
	&lt;li&gt;यह उष्ण कटिबंध से उत्तरी अटलांटिक तक गर्म जल पहुंचाता है, जिससे यह जिन क्षेत्रों से होकर गुजरता है वहां की जलवायु पर प्रभाव डालता है।&lt;/li&gt;
	&lt;li&gt;गल्फ स्ट्रीम का पूर्वी उत्तरी अमेरिका और पश्चिमी यूरोप के मौसम और जलवायु पर उल्लेखनीय प्रभाव पड़ता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;To determine the time in London, United Kingdom, based on the given time in India, we need to consider the time difference between India Standard Time (IST) and Greenwich Mean Time (GMT) or British Summer Time (BST), depending on the time of year.&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;India Standard Time (IST) is UTC+5:30, and London, located near Greenwich, follows Greenwich Mean Time (GMT) or British Summer Time (BST), which is UTC+0 or UTC+1 (during daylight saving time).&lt;/p&gt;

&lt;p&gt;Given that the time in India is 7 am, let&amp;#39;s calculate the corresponding time in London:&lt;/p&gt;

&lt;p&gt;Time in India: 7 am (IST)&lt;/p&gt;

&lt;p&gt;Time difference between India and London: IST is UTC+5:30, and London is UTC+0 or UTC+1&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Calculating the corresponding time in London:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;7 am (IST) - 5 hours and 30 minutes (time difference) = 1:30 am (GMT)&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;So, the correct option is (3) 1 ∶ 30 am. If it is 7 am in India, the time in London, located near Greenwich, would be 1:30 am in Greenwich Mean Time (GMT).&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;​&lt;/span&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;1&amp;nbsp;∶&amp;nbsp;30&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;u&gt;&lt;strong&gt;पूर्वाह्न&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;&lt;/span&gt;है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;भारत में दिए गए समय के आधार पर लंदन, यूनाइटेड किंगडम में समय निर्धारित करने के लिए हमें वर्ष के समय के आधार पर भारत मानक समय (IST) और ग्रीनविच मीन टाइम (GMT) या ब्रिटिश ग्रीष्मकालीन समय (BST) के बीच समय अंतर पर विचार करना होगा।&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;भारत का मानक समय (IST) UTC+5:30 है और ग्रीनविच के पास स्थित लंदन, ग्रीनविच मीन टाइम (GMT) या ब्रिटिश समर टाइम (BST) का अनुसरण करता है, जो UTC+0 या UTC+1 है (डेलाइट सेविंग टाइम के दौरान)&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;यह देखते हुए कि भारत में समय सुबह 7 बजे है, आइए लंदन में इसी समय की गणना करें:&lt;/p&gt;

&lt;p&gt;भारत में समय: सुबह 7 बजे (IST)&lt;/p&gt;

&lt;p&gt;भारत और लंदन के बीच समय का अंतर: IST UTC+5:30 है, और लंदन UTC+0 या UTC+1 है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;लंदन में संगत समय की गणना:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;सुबह 7 बजे (IST) - 5 घंटे और 30 मिनट (समय अंतर) = 1:30 पूर्वाह्न (GMT)&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;अतः सही विकल्प (3) 1 ∶ 30 पूर्वाह्न है। यदि भारत में सुबह के 7 बजे हैं, तो ग्रीनविच के पास स्थित लंदन में ग्रीनविच मीन टाइम (GMT) में समय 1:30 बजे होगा।&lt;/strong&gt;&lt;/p&gt;

questions.statement:
&lt;p&gt;Read the Statements (A) and (R) and choose the correct option.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Assertion (A) :&lt;/strong&gt; The air is cold in areas having lower temperature.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Reason (R) :&lt;/strong&gt; Air is heavy in cold areas.&lt;/p&gt;<br>&lt;p&gt;निम्नलिखित कथनों (A) तथा (R) को पढ़ें तथा सही विकल्प का चयन कीजिए।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;कथन (A) :&lt;/strong&gt; कम तापमान वाले क्षेत्रों में वायु ठंडी होती है।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;कारण (R) :&lt;/strong&gt; ठंडे क्षेत्रों में वायु भारी होती है।&lt;/p&gt;

questions.explanation:
&lt;p&gt;&lt;strong&gt;Both these statements (A) and (R) are true and (R) is not the correct explanation of (A).​&lt;br /&gt;
&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Statement (A) asserts that the air is cold in areas with lower temperatures&lt;/strong&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;This statement is generally true because lower temperatures in an area often result in colder air.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;Statement (R) claims that air is heavy in cold areas.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&amp;quot;Air is heavy in cold areas,&amp;quot; it&amp;#39;s somewhat misleading. While it&amp;#39;s true cold air is denser than warm air, stating it as &amp;quot;heavy&amp;quot; may lead to confusion. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;The density does increase, causing the air to settle closer to the ground, but the weight does not significantly change.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Therefore, the correct option would be:&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;Both these statements (A) and (R) are true but (R) is not the correct explanation of (A).&lt;/span&gt;&lt;/div&gt;<br><br>&lt;p&gt;&lt;strong&gt;(A) और (R) दोनों सही हैं और (R), (A) की सही व्याख्या&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;नहीं&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt; है।&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;कथन (A) में दावा किया गया है कि कम तापमान वाले क्षेत्रों में हवा ठंडी है&lt;/strong&gt; ।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह कथन आम तौर पर सत्य है क्योंकि किसी क्षेत्र में कम तापमान के परिणामस्वरूप अक्सर ठंडी हवा आती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;कथन (R) का दावा है कि ठंडे क्षेत्रों में हवा भारी होती है।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ठंडे क्षेत्रों में, कम तापमान के कारण हवा वास्तव में सघन हो सकती है, जिससे यह अधिक सघन हो जाती है।&lt;/li&gt;
	&lt;li&gt;हालाँकि, इसे &amp;quot;भारी&amp;quot; बताने से भ्रम पैदा हो सकता है।&lt;/li&gt;
	&lt;li&gt;ठंडी हवा गर्म हवा की तुलना में सघन होती है क्योंकि इसके अणु एक-दूसरे के करीब होते हैं, इसलिए नहीं कि यह स्वाभाविक रूप से भारी होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अब, दोनों कथनों पर विचार करें:&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;विकल्प 1) ये दोनों कथन (A) और (R) सत्य हैं, और (R), (A) का सही स्पष्टीकरण &lt;span style=&quot;&quot;&gt;नहीं&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;है, यह मानते हुए कि ठंडी हवा का घनत्व उसके कम तापमान के कारण होता है, जो इसे सघन बनाता है लेकिन जरूरी नहीं कि &amp;quot;प्रति इकाई आयतन वजन&amp;quot; के संदर्भ में भारी हो।&lt;/strong&gt;&lt;/p&gt;

questions.statement:
&lt;p&gt;Consider the following sentences for physical features of India and choose the correct option:&lt;/p&gt;

&lt;p&gt;(A) Many popular hill stations are situated in Middle Himalaya.&lt;/p&gt;

&lt;p&gt;(B) Northern plains are highly populated areas because river plains have fertile land for cultivation.&lt;/p&gt;

&lt;p&gt;(C) Western ghats are rich in minerals and are highly populated.&lt;/p&gt;<br>&lt;p&gt;भारत की भौगोलिक विशेषताओं के बारे में दिए गए कथनों को पढ़िए तथा सही विकल्प का चुनाव कीजिए।&lt;/p&gt;

&lt;p&gt;(A) बहुत से लोकप्रिय पहाड़ी स्थान मध्य हिमालय में स्थित हैं।&lt;/p&gt;

&lt;p&gt;(B) उत्तरी मैदानों में अधिक जनसंख्या है क्योंकि यहाँ कृषि हेतु ऊपजाऊ भूमि है।&lt;/p&gt;

&lt;p&gt;(C) पश्चिमी घाटों में प्रचूर मात्रा में खनिज पाए जाते हैं तथा यहाँ अधिक जनसंख्या है।&lt;/p&gt;

questions.explanation:
&lt;p&gt;&lt;strong&gt;The correct option is (3) Only (A) and (B) are correct.&lt;/strong&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(A) Many popular hill stations are situated in the Middle Himalaya.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;This statement is correct.&lt;/li&gt;
	&lt;li&gt;The Middle Himalaya region of India is known for its scenic beauty and is home to several popular hill stations such as Shimla, Nainital, and Mussoorie.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;(B) Northern plains are highly populated areas because river plains have fertile land for cultivation.&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;This statement is also correct.&lt;/li&gt;
	&lt;li&gt;The Northern plains of India, also known as the Indo-Gangetic plains, are characterized by the fertile alluvial soil deposited by rivers such as the Ganges, Brahmaputra, and Yamuna.&lt;/li&gt;
	&lt;li&gt;The availability of fertile land and the presence of abundant water resources make this region highly suitable for agriculture.&lt;/li&gt;
	&lt;li&gt;As a result, it has attracted a dense population due to agricultural activities.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;(C) Western Ghats are rich in minerals and are highly populated.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;This statement is incorrect.&lt;/li&gt;
	&lt;li&gt;While the Western Ghats of India are indeed rich in biodiversity and are recognized as a biodiversity hotspot, they are not primarily known for mineral resources.&lt;/li&gt;
	&lt;li&gt;The Western Ghats are a mountain range parallel to the western coast of India, and they are home to several national parks, wildlife sanctuaries, and ecologically significant areas.&lt;/li&gt;
	&lt;li&gt;However, the population density in the Western Ghats region is relatively lower compared to the Northern plains and other densely populated areas of India.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;Therefore, the correct option is (3) Only (A) and (B) are correct.&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;सही विकल्प यह है कि&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;केवल&amp;nbsp;(A)&amp;nbsp;तथा&amp;nbsp;(B)&amp;nbsp;सही हैं&lt;/span&gt;।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(A) कई लोकप्रिय पहाड़ी स्थान&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;मध्य हिमालय में स्थित हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह कथन सही है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;भारत का मध्य हिमालय क्षेत्र अपनी प्राकृतिक सुंदरता के लिए जाना जाता है और यह शिमला, नैनीताल एवं मसूरी जैसे कई लोकप्रिय पहाड़ी स्थानों का घर है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;(B) उत्तरी मैदान अत्यधिक आबादी वाले क्षेत्र हैं क्योंकि नदी के मैदानों में खेती के लिए उपजाऊ भूमि होती है।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह कथन भी सही है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;भारत के उत्तरी मैदान, जिसे भारत-गंगा के मैदान के रूप में भी जाना जाता है, की विशेषता गंगा, ब्रह्मपुत्र और यमुना जैसी नदियों द्वारा जमा की गई उपजाऊ जलोढ़ मिट्टी है।&lt;/li&gt;
	&lt;li&gt;उपजाऊ भूमि की उपलब्धता और प्रचुर जल संसाधनों की उपस्थिति इस क्षेत्र को कृषि के लिए अत्यधिक उपयुक्त बनाती है।&lt;/li&gt;
	&lt;li&gt;परिणामस्वरूप, कृषि गतिविधियों के कारण इसने घनी आबादी को आकर्षित किया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;(C) पश्चिमी घाट खनिजों से समृद्ध हैं और अत्यधिक आबादी वाले हैं।&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह कथन ग़लत है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;जबकि भारत के पश्चिमी घाट वास्तव में जैव विविधता में समृद्ध हैं और जैव विविधता हॉटस्पॉट के रूप में पहचाने जाते हैं, वे मुख्य रूप से खनिज संसाधनों के लिए नहीं जाने जाते हैं।&lt;/li&gt;
	&lt;li&gt;पश्चिमी घाट भारत के पश्चिमी तट के समानांतर एक पर्वत श्रृंखला है और वे कई राष्ट्रीय उद्यानों, वन्यजीव अभयारण्यों और पारिस्थितिक रूप से महत्वपूर्ण क्षेत्रों का घर हैं।&lt;/li&gt;
	&lt;li&gt;हालाँकि, पश्चिमी घाट क्षेत्र में जनसंख्या घनत्व उत्तरी मैदानी इलाकों एवं भारत के अन्य घनी आबादी वाले क्षेत्रों की तुलना में अपेक्षाकृत कम है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;अतः सही विकल्प यह है कि&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;केवल&amp;nbsp;(A)&amp;nbsp;तथा&amp;nbsp;(B)&amp;nbsp;सही हैं&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Aman is travelling from Ranchi to Hyderabad. He is moving towards South West direction.&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Hyderabad is located to the south-west of Ranchi on a map.&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage6458f8c5d98e2ef788d5959f.png&quot; style=&quot;border-width: 1px; border-style: solid; height: 190px; width: 350px;&quot; /&gt;&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;When Aman travels from Ranchi to Hyderabad, he is moving in a South West direction.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;This means that he is moving towards the direction that is midway between South and West, which is approximately a direction of 225 degrees on a compass.&lt;/li&gt;
	&lt;li&gt;In geographical terms, &lt;strong&gt;Ranchi is located in the eastern part&lt;/strong&gt; of India, specifically in the state of Jharkhand.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Hyderabad&lt;/strong&gt;, on the other hand, is situated in the &lt;strong&gt;southern part of India&lt;/strong&gt;, in the state of Telangana.&lt;/li&gt;
	&lt;li&gt;So, when Aman travels from Ranchi to Hyderabad, he is moving in a direction that is primarily towards the south, but also towards the west, which is why it is called South West direction.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;अमन रांची से हैदराबाद जा रहा है। वह दक्षिण पश्चिम दिशा की ओर बढ़ रहा है।&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;हैदराबाद मानचित्र पर रांची के दक्षिण-पश्चिम में स्थित है।&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage6458f8c5d98e2ef788d5959f.png&quot; style=&quot;border-width: 1px; border-style: solid; height: 190px; width: 350px;&quot; /&gt;&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;जब अमन रांची से हैदराबाद की यात्रा करता है, तो वह दक्षिण-पश्चिम दिशा में चल रहा होता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इसका अर्थ है कि वह उस दिशा की ओर बढ़ रहा है जो दक्षिण और पश्चिम के बीच में है, जो कम्पास पर लगभग 225 डिग्री की दिशा है।&lt;/li&gt;
	&lt;li&gt;भौगोलिक दृष्टि से, &lt;strong&gt;रांची भारत के पूर्वी भाग में स्थित है,&lt;/strong&gt; विशेष रूप से झारखंड राज्य में।&lt;/li&gt;
	&lt;li&gt;दूसरी ओर, हैदराबाद, भारत के दक्षिणी भाग में, तेलंगाना राज्य में स्थित है।&lt;/li&gt;
	&lt;li&gt;इसलिए, जब अमन रांची से हैदराबाद की यात्रा करता है, तो वह उस दिशा में जा रहा है जो मुख्य रूप से दक्षिण की ओर है, लेकिन पश्चिम की ओर भी है, इसलिए इसे दक्षिण-पश्चिम दिशा कहा जाता है।&lt;/li&gt;
&lt;/ul&gt;

